package handler

import (
	"context"
	"encoding/json"
	"io"
	"net/http"

	"github.com/gin-gonic/gin"
	"github.com/ravencloak-org/Raven/internal/middleware"
	"github.com/ravencloak-org/Raven/internal/model"
	"github.com/ravencloak-org/Raven/pkg/apierror"
)

// BillingServicer is the interface the handler requires from the billing service layer.
type BillingServicer interface {
	GetPlans() []model.Plan
	CreateSubscription(ctx context.Context, orgID string, req model.CreateSubscriptionRequest) (*model.Subscription, error)
	CancelSubscription(ctx context.Context, orgID string, subscriptionID string) error
	CreatePaymentIntent(ctx context.Context, orgID string, req model.CreatePaymentIntentRequest) (*model.PaymentIntent, error)
	VerifyWebhookSignature(payload []byte, signature string) error
	HandleWebhook(ctx context.Context, event model.HyperswitchWebhookPayload) error
}

// BillingHandler handles HTTP requests for billing and subscription management.
type BillingHandler struct {
	svc BillingServicer
}

// NewBillingHandler creates a new BillingHandler.
func NewBillingHandler(svc BillingServicer) *BillingHandler {
	return &BillingHandler{svc: svc}
}

// GetPlans handles GET /api/v1/billing/plans.
//
// @Summary     List billing plans
// @Tags        billing
// @Produce     json
// @Security    BearerAuth
// @Success     200 {array} model.Plan
// @Router      /billing/plans [get]
func (h *BillingHandler) GetPlans(c *gin.Context) {
	plans := h.svc.GetPlans()
	c.JSON(http.StatusOK, plans)
}

// Subscribe handles POST /api/v1/billing/subscribe.
//
// @Summary     Create subscription
// @Tags        billing
// @Accept      json
// @Produce     json
// @Security    BearerAuth
// @Param       request body model.CreateSubscriptionRequest true "Subscription payload"
// @Success     201 {object} model.Subscription
// @Failure     422 {object} apierror.AppError
// @Failure     401 {object} apierror.AppError
// @Failure     500 {object} apierror.AppError
// @Router      /billing/subscribe [post]
func (h *BillingHandler) Subscribe(c *gin.Context) {
	orgID, exists := c.Get(string(middleware.ContextKeyOrgID))
	if !exists {
		c.AbortWithStatusJSON(http.StatusUnauthorized, apierror.AppError{
			Code:    http.StatusUnauthorized,
			Message: "Unauthorized",
			Detail:  "missing organisation context",
		})
		return
	}

	var req model.CreateSubscriptionRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.AbortWithStatusJSON(http.StatusUnprocessableEntity, apierror.AppError{
			Code:    http.StatusUnprocessableEntity,
			Message: "Unprocessable Entity",
			Detail:  err.Error(),
		})
		return
	}

	sub, err := h.svc.CreateSubscription(c.Request.Context(), orgID.(string), req)
	if err != nil {
		_ = c.Error(err)
		c.Abort()
		return
	}
	c.JSON(http.StatusCreated, sub)
}

// Unsubscribe handles DELETE /api/v1/billing/subscribe.
//
// @Summary     Cancel subscription
// @Tags        billing
// @Produce     json
// @Security    BearerAuth
// @Param       subscription_id query string true "Subscription ID to cancel"
// @Success     204
// @Failure     401 {object} apierror.AppError
// @Failure     404 {object} apierror.AppError
// @Failure     500 {object} apierror.AppError
// @Router      /billing/subscribe [delete]
func (h *BillingHandler) Unsubscribe(c *gin.Context) {
	orgID, exists := c.Get(string(middleware.ContextKeyOrgID))
	if !exists {
		c.AbortWithStatusJSON(http.StatusUnauthorized, apierror.AppError{
			Code:    http.StatusUnauthorized,
			Message: "Unauthorized",
			Detail:  "missing organisation context",
		})
		return
	}

	subscriptionID := c.Query("subscription_id")
	if subscriptionID == "" {
		c.AbortWithStatusJSON(http.StatusUnprocessableEntity, apierror.AppError{
			Code:    http.StatusUnprocessableEntity,
			Message: "Unprocessable Entity",
			Detail:  "subscription_id query parameter is required",
		})
		return
	}

	if err := h.svc.CancelSubscription(c.Request.Context(), orgID.(string), subscriptionID); err != nil {
		_ = c.Error(err)
		c.Abort()
		return
	}
	c.Status(http.StatusNoContent)
}

// CreatePaymentIntent handles POST /api/v1/billing/payment-intents.
//
// @Summary     Create payment intent
// @Tags        billing
// @Accept      json
// @Produce     json
// @Security    BearerAuth
// @Param       request body model.CreatePaymentIntentRequest true "Payment intent payload"
// @Success     201 {object} model.PaymentIntent
// @Failure     422 {object} apierror.AppError
// @Failure     401 {object} apierror.AppError
// @Failure     500 {object} apierror.AppError
// @Router      /billing/payment-intents [post]
func (h *BillingHandler) CreatePaymentIntent(c *gin.Context) {
	orgID, exists := c.Get(string(middleware.ContextKeyOrgID))
	if !exists {
		c.AbortWithStatusJSON(http.StatusUnauthorized, apierror.AppError{
			Code:    http.StatusUnauthorized,
			Message: "Unauthorized",
			Detail:  "missing organisation context",
		})
		return
	}

	var req model.CreatePaymentIntentRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.AbortWithStatusJSON(http.StatusUnprocessableEntity, apierror.AppError{
			Code:    http.StatusUnprocessableEntity,
			Message: "Unprocessable Entity",
			Detail:  err.Error(),
		})
		return
	}

	pi, err := h.svc.CreatePaymentIntent(c.Request.Context(), orgID.(string), req)
	if err != nil {
		_ = c.Error(err)
		c.Abort()
		return
	}
	c.JSON(http.StatusCreated, pi)
}

// Webhook handles POST /api/v1/billing/webhook.
// This endpoint is called by Hyperswitch to notify about payment events.
// It does NOT require JWT authentication; it uses webhook signature verification.
//
// @Summary     Hyperswitch webhook
// @Tags        billing
// @Accept      json
// @Produce     json
// @Param       X-Webhook-Signature header string true "HMAC-SHA256 signature"
// @Success     200 {object} map[string]string
// @Failure     401 {object} apierror.AppError
// @Failure     400 {object} apierror.AppError
// @Router      /billing/webhook [post]
func (h *BillingHandler) Webhook(c *gin.Context) {
	payload, err := io.ReadAll(c.Request.Body)
	if err != nil {
		c.AbortWithStatusJSON(http.StatusBadRequest, apierror.AppError{
			Code:    http.StatusBadRequest,
			Message: "Bad Request",
			Detail:  "failed to read request body",
		})
		return
	}

	signature := c.GetHeader("X-Webhook-Signature")
	if err := h.svc.VerifyWebhookSignature(payload, signature); err != nil {
		_ = c.Error(err)
		c.Abort()
		return
	}

	// Since we already consumed the body for signature verification,
	// unmarshal from the raw payload bytes directly.
	var event model.HyperswitchWebhookPayload
	if err := json.Unmarshal(payload, &event); err != nil {
		c.AbortWithStatusJSON(http.StatusBadRequest, apierror.AppError{
			Code:    http.StatusBadRequest,
			Message: "Bad Request",
			Detail:  "invalid webhook payload: " + err.Error(),
		})
		return
	}

	if err := h.svc.HandleWebhook(c.Request.Context(), event); err != nil {
		_ = c.Error(err)
		c.Abort()
		return
	}

	c.JSON(http.StatusOK, gin.H{"status": "ok"})
}

package service

import (
	"bytes"
	"context"
	"crypto/hmac"
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"log/slog"
	"net/http"
	"time"

	"github.com/jackc/pgx/v5"
	"github.com/jackc/pgx/v5/pgxpool"

	"github.com/ravencloak-org/Raven/internal/db"
	"github.com/ravencloak-org/Raven/internal/model"
	"github.com/ravencloak-org/Raven/pkg/apierror"
)

// BillingRepository is the persistence interface required by BillingService.
type BillingRepository interface {
	UpsertSubscription(ctx context.Context, tx pgx.Tx, s *model.Subscription) (*model.Subscription, error)
	GetActiveSubscription(ctx context.Context, tx pgx.Tx, orgID string) (*model.Subscription, error)
	GetSubscriptionByID(ctx context.Context, tx pgx.Tx, subscriptionID string) (*model.Subscription, error)
	GetSubscriptionByHyperswitchID(ctx context.Context, hyperswitchID string) (*model.Subscription, error)
	UpdateSubscriptionStatus(ctx context.Context, tx pgx.Tx, subscriptionID string, status model.SubscriptionStatus, periodEnd *time.Time) error

	CreatePaymentIntent(ctx context.Context, tx pgx.Tx, pi *model.PaymentIntent) (*model.PaymentIntent, error)
	GetPaymentIntentByHyperswitchID(ctx context.Context, hyperswitchPaymentID string) (*model.PaymentIntent, error)
	UpdatePaymentIntentStatus(ctx context.Context, hyperswitchPaymentID string, status model.PaymentIntentStatus) error
}

// BillingService contains business logic for subscription and payment management
// via the Hyperswitch payment orchestration platform with Razorpay as the gateway.
type BillingService struct {
	repo          BillingRepository
	pool          *pgxpool.Pool
	httpClient    *http.Client
	baseURL       string
	apiKey        string
	webhookSecret string
	razorpayKeyID string
	plans         map[string]model.Plan
}

// NewBillingService creates a new BillingService.
// baseURL is the Hyperswitch API base URL (e.g. "https://sandbox.hyperswitch.io").
// apiKey is the Hyperswitch merchant API key.
// webhookSecret is used to verify Hyperswitch webhook HMAC-SHA256 signatures.
// razorpayKeyID is the Razorpay public key ID surfaced to the frontend for UPI/card collection.
func NewBillingService(repo BillingRepository, pool *pgxpool.Pool, baseURL, apiKey, webhookSecret, razorpayKeyID string) *BillingService {
	plans := make(map[string]model.Plan)
	for _, p := range model.DefaultPlans() {
		plans[p.ID] = p
	}
	return &BillingService{
		repo: repo,
		pool: pool,
		httpClient: &http.Client{
			Timeout: 30 * time.Second,
		},
		baseURL:       baseURL,
		apiKey:        apiKey,
		webhookSecret: webhookSecret,
		razorpayKeyID: razorpayKeyID,
		plans:         plans,
	}
}

// GetPlans returns the available billing plans.
func (s *BillingService) GetPlans() []model.Plan {
	return model.DefaultPlans()
}

// getPlanByID returns a plan by ID, or a not-found error.
func (s *BillingService) getPlanByID(planID string) (*model.Plan, error) {
	p, ok := s.plans[planID]
	if !ok {
		return nil, apierror.NewNotFound("plan not found: " + planID)
	}
	return &p, nil
}

// CreateSubscription creates a new subscription for the given organisation.
//
// For the free plan no Hyperswitch call is made. For paid plans a Hyperswitch
// payment is created so the frontend can collect the first payment; the
// subscription is recorded as active once the payment_succeeded webhook fires.
// Calling this again while an active subscription already exists replaces it
// (upsert semantics) so callers can upgrade/downgrade plans idempotently.
func (s *BillingService) CreateSubscription(ctx context.Context, orgID string, req model.CreateSubscriptionRequest) (*model.Subscription, error) {
	plan, err := s.getPlanByID(req.PlanID)
	if err != nil {
		return nil, err
	}

	now := time.Now().UTC()

	if plan.Tier == model.PlanTierFree {
		// Free plan — no payment required; activate immediately.
		sub := &model.Subscription{
			OrgID:              orgID,
			PlanID:             plan.ID,
			Status:             model.SubscriptionStatusActive,
			CurrentPeriodStart: now,
			CurrentPeriodEnd:   now.AddDate(0, 1, 0),
			CreatedAt:          now,
		}
		var persisted *model.Subscription
		if err := db.WithOrgID(ctx, s.pool, orgID, func(tx pgx.Tx) error {
			var e error
			persisted, e = s.repo.UpsertSubscription(ctx, tx, sub)
			return e
		}); err != nil {
			slog.ErrorContext(ctx, "BillingService.CreateSubscription db error", "error", err, "org_id", orgID)
			return nil, apierror.NewInternal("failed to persist free subscription")
		}
		slog.InfoContext(ctx, "free subscription activated", "org_id", orgID, "subscription_id", persisted.ID)
		return persisted, nil
	}

	// Paid plan — create a Hyperswitch payment intent for the first billing cycle.
	// The subscription is recorded as trialing; it transitions to active on payment_succeeded.
	hsPaymentID, clientSecret, err := s.createHyperswitchPayment(ctx, orgID, plan.PriceMonthly, "INR")
	if err != nil {
		return nil, apierror.NewInternal("failed to create Hyperswitch payment: " + err.Error())
	}

	sub := &model.Subscription{
		OrgID:                     orgID,
		PlanID:                    plan.ID,
		Status:                    model.SubscriptionStatusTrialing,
		HyperswitchSubscriptionID: hsPaymentID,
		CurrentPeriodStart:        now,
		CurrentPeriodEnd:          now.AddDate(0, 1, 0),
		CreatedAt:                 now,
	}

	// Also record the payment intent for idempotent webhook processing.
	pi := &model.PaymentIntent{
		OrgID:                orgID,
		Amount:               plan.PriceMonthly,
		Currency:             "INR",
		Status:               model.PaymentIntentStatusRequiresPayment,
		HyperswitchPaymentID: hsPaymentID,
		ClientSecret:         clientSecret,
		CreatedAt:            now,
	}

	var persisted *model.Subscription
	if err := db.WithOrgID(ctx, s.pool, orgID, func(tx pgx.Tx) error {
		var e error
		persisted, e = s.repo.UpsertSubscription(ctx, tx, sub)
		if e != nil {
			return e
		}
		_, e = s.repo.CreatePaymentIntent(ctx, tx, pi)
		return e
	}); err != nil {
		slog.ErrorContext(ctx, "BillingService.CreateSubscription db error", "error", err, "org_id", orgID)
		return nil, apierror.NewInternal("failed to persist subscription")
	}

	slog.InfoContext(ctx, "paid subscription pending payment",
		"org_id", orgID,
		"subscription_id", persisted.ID,
		"hs_payment_id", hsPaymentID,
		"plan_id", plan.ID,
	)
	// Return the subscription enriched with the client_secret so the frontend
	// can open the Hyperswitch SDK / Razorpay checkout.
	persisted.HyperswitchSubscriptionID = clientSecret
	return persisted, nil
}

// CancelSubscription cancels the subscription for the given organisation.
func (s *BillingService) CancelSubscription(ctx context.Context, orgID string, subscriptionID string) error {
	var sub *model.Subscription
	if err := db.WithOrgID(ctx, s.pool, orgID, func(tx pgx.Tx) error {
		var e error
		sub, e = s.repo.GetSubscriptionByID(ctx, tx, subscriptionID)
		return e
	}); err != nil {
		if errors.Is(err, pgx.ErrNoRows) {
			return apierror.NewNotFound("subscription not found: " + subscriptionID)
		}
		return apierror.NewInternal("failed to fetch subscription")
	}

	if sub.OrgID != orgID {
		return apierror.NewNotFound("subscription not found: " + subscriptionID)
	}

	// Attempt to cancel in Hyperswitch when an external payment ID is present.
	if sub.HyperswitchSubscriptionID != "" {
		if err := s.cancelHyperswitchPayment(ctx, sub.HyperswitchSubscriptionID); err != nil {
			// Log but do not block local cancellation — the payment may already be finalized.
			slog.WarnContext(ctx, "Hyperswitch cancel call failed; proceeding with local cancellation",
				"error", err,
				"hs_payment_id", sub.HyperswitchSubscriptionID,
			)
		}
	}

	if err := db.WithOrgID(ctx, s.pool, orgID, func(tx pgx.Tx) error {
		return s.repo.UpdateSubscriptionStatus(ctx, tx, subscriptionID, model.SubscriptionStatusCanceled, nil)
	}); err != nil {
		return apierror.NewInternal("failed to update subscription status")
	}

	slog.InfoContext(ctx, "subscription cancelled", "org_id", orgID, "subscription_id", subscriptionID)
	return nil
}

// CreatePaymentIntent creates a standalone one-off payment intent via Hyperswitch
// and persists it to the database for idempotent webhook processing.
func (s *BillingService) CreatePaymentIntent(ctx context.Context, orgID string, req model.CreatePaymentIntentRequest) (*model.PaymentIntent, error) {
	hsPaymentID, clientSecret, err := s.createHyperswitchPayment(ctx, orgID, req.Amount, req.Currency)
	if err != nil {
		return nil, apierror.NewInternal("failed to create Hyperswitch payment: " + err.Error())
	}

	now := time.Now().UTC()
	pi := &model.PaymentIntent{
		OrgID:                orgID,
		Amount:               req.Amount,
		Currency:             req.Currency,
		Status:               model.PaymentIntentStatusRequiresPayment,
		HyperswitchPaymentID: hsPaymentID,
		ClientSecret:         clientSecret,
		CreatedAt:            now,
	}

	var persisted *model.PaymentIntent
	if err := db.WithOrgID(ctx, s.pool, orgID, func(tx pgx.Tx) error {
		var e error
		persisted, e = s.repo.CreatePaymentIntent(ctx, tx, pi)
		return e
	}); err != nil {
		slog.ErrorContext(ctx, "BillingService.CreatePaymentIntent db error", "error", err, "org_id", orgID)
		return nil, apierror.NewInternal("failed to persist payment intent")
	}

	slog.InfoContext(ctx, "payment intent created",
		"org_id", orgID,
		"payment_intent_id", persisted.ID,
		"hs_payment_id", hsPaymentID,
	)
	return persisted, nil
}

// VerifyWebhookSignature verifies the Hyperswitch webhook HMAC-SHA256 signature.
// Returns nil if the signature is valid or if no webhook secret is configured (dev mode).
func (s *BillingService) VerifyWebhookSignature(payload []byte, signature string) error {
	if s.webhookSecret == "" {
		slog.Warn("Hyperswitch webhook signature validation skipped: webhook_secret not configured")
		return nil
	}

	mac := hmac.New(sha256.New, []byte(s.webhookSecret))
	mac.Write(payload)
	expected := hex.EncodeToString(mac.Sum(nil))

	if !hmac.Equal([]byte(expected), []byte(signature)) {
		return apierror.NewUnauthorized("invalid webhook signature")
	}
	return nil
}

// HandleWebhook processes a verified Hyperswitch webhook event and updates
// the subscription state machine.
//
// Idempotency: duplicate events for the same payment_id are safe because the
// DB updates are idempotent (setting the same status twice is a no-op).
func (s *BillingService) HandleWebhook(ctx context.Context, event model.HyperswitchWebhookPayload) error {
	switch event.EventType {
	case "payment_succeeded", "payment.succeeded":
		return s.handlePaymentSucceeded(ctx, event.Content)

	case "payment_failed", "payment.failed":
		return s.handlePaymentFailed(ctx, event.Content)

	case "subscription_cancelled", "subscription.cancelled":
		return s.handleSubscriptionCancelled(ctx, event.Content)

	default:
		slog.InfoContext(ctx, "unhandled Hyperswitch webhook event", "event_type", event.EventType)
		return nil
	}
}

// handlePaymentSucceeded activates the linked subscription when a payment succeeds.
func (s *BillingService) handlePaymentSucceeded(ctx context.Context, content map[string]any) error {
	paymentID := extractPaymentID(content)
	if paymentID == "" {
		slog.WarnContext(ctx, "payment_succeeded webhook missing payment_id")
		return nil
	}

	// Update payment intent status.
	if err := s.repo.UpdatePaymentIntentStatus(ctx, paymentID, model.PaymentIntentStatusSucceeded); err != nil {
		// Not fatal if the intent doesn't exist (may be a sub-payment we don't track).
		slog.WarnContext(ctx, "could not update payment intent status", "hs_payment_id", paymentID, "error", err)
	}

	// Look up the associated subscription.
	sub, err := s.repo.GetSubscriptionByHyperswitchID(ctx, paymentID)
	if err != nil {
		if errors.Is(err, pgx.ErrNoRows) {
			// Payment not linked to a subscription — standalone payment intent, nothing to activate.
			slog.InfoContext(ctx, "payment_succeeded: no linked subscription found", "hs_payment_id", paymentID)
			return nil
		}
		return fmt.Errorf("handlePaymentSucceeded: lookup subscription: %w", err)
	}

	// Transition to active and extend the billing period by one month.
	newPeriodEnd := time.Now().UTC().AddDate(0, 1, 0)
	if err := db.WithOrgID(ctx, s.pool, sub.OrgID, func(tx pgx.Tx) error {
		return s.repo.UpdateSubscriptionStatus(ctx, tx, sub.ID, model.SubscriptionStatusActive, &newPeriodEnd)
	}); err != nil {
		return fmt.Errorf("handlePaymentSucceeded: activate subscription: %w", err)
	}

	slog.InfoContext(ctx, "subscription activated via payment_succeeded",
		"subscription_id", sub.ID,
		"org_id", sub.OrgID,
		"hs_payment_id", paymentID,
	)
	return nil
}

// handlePaymentFailed marks the subscription as past_due and the payment intent as failed.
func (s *BillingService) handlePaymentFailed(ctx context.Context, content map[string]any) error {
	paymentID := extractPaymentID(content)
	if paymentID == "" {
		slog.WarnContext(ctx, "payment_failed webhook missing payment_id")
		return nil
	}

	// Update payment intent status.
	if err := s.repo.UpdatePaymentIntentStatus(ctx, paymentID, model.PaymentIntentStatusFailed); err != nil {
		slog.WarnContext(ctx, "could not update payment intent status", "hs_payment_id", paymentID, "error", err)
	}

	// Downgrade linked subscription to past_due.
	sub, err := s.repo.GetSubscriptionByHyperswitchID(ctx, paymentID)
	if err != nil {
		if errors.Is(err, pgx.ErrNoRows) {
			slog.InfoContext(ctx, "payment_failed: no linked subscription found", "hs_payment_id", paymentID)
			return nil
		}
		return fmt.Errorf("handlePaymentFailed: lookup subscription: %w", err)
	}

	if err := db.WithOrgID(ctx, s.pool, sub.OrgID, func(tx pgx.Tx) error {
		return s.repo.UpdateSubscriptionStatus(ctx, tx, sub.ID, model.SubscriptionStatusPastDue, nil)
	}); err != nil {
		return fmt.Errorf("handlePaymentFailed: set past_due: %w", err)
	}

	slog.InfoContext(ctx, "subscription set to past_due via payment_failed",
		"subscription_id", sub.ID,
		"org_id", sub.OrgID,
		"hs_payment_id", paymentID,
	)
	return nil
}

// handleSubscriptionCancelled downgrades the org to free tier on subscription cancellation.
func (s *BillingService) handleSubscriptionCancelled(ctx context.Context, content map[string]any) error {
	// Hyperswitch subscription.cancelled uses subscription_id or payment_id.
	subscriptionID := extractStringField(content, "subscription_id", "payment_id", "id")
	if subscriptionID == "" {
		slog.WarnContext(ctx, "subscription.cancelled webhook missing subscription identifier")
		return nil
	}

	sub, err := s.repo.GetSubscriptionByHyperswitchID(ctx, subscriptionID)
	if err != nil {
		if errors.Is(err, pgx.ErrNoRows) {
			slog.InfoContext(ctx, "subscription.cancelled: no linked subscription found", "hs_id", subscriptionID)
			return nil
		}
		return fmt.Errorf("handleSubscriptionCancelled: lookup: %w", err)
	}

	if err := db.WithOrgID(ctx, s.pool, sub.OrgID, func(tx pgx.Tx) error {
		return s.repo.UpdateSubscriptionStatus(ctx, tx, sub.ID, model.SubscriptionStatusCanceled, nil)
	}); err != nil {
		return fmt.Errorf("handleSubscriptionCancelled: cancel: %w", err)
	}

	slog.InfoContext(ctx, "subscription cancelled via webhook",
		"subscription_id", sub.ID,
		"org_id", sub.OrgID,
	)
	return nil
}

// --- Hyperswitch HTTP helpers ---

// createHyperswitchPayment creates a payment via the Hyperswitch /payments endpoint
// with Razorpay as the connector. Returns (payment_id, client_secret, error).
func (s *BillingService) createHyperswitchPayment(ctx context.Context, orgID string, amount int64, currency string) (string, string, error) {
	body := map[string]any{
		"amount":      amount,
		"currency":    currency,
		"customer_id": orgID,
		// Route payment through Razorpay for UPI/card collection in India.
		"routing": map[string]any{
			"type": "single",
			"data": "razorpay",
		},
		"payment_method_types": []string{"upi", "card"},
		"metadata": map[string]string{
			"org_id": orgID,
		},
	}

	resp, err := s.hyperswitchRequest(ctx, http.MethodPost, "/payments", body)
	if err != nil {
		return "", "", err
	}

	paymentID, _ := resp["payment_id"].(string)
	clientSecret, _ := resp["client_secret"].(string)
	if paymentID == "" {
		return "", "", fmt.Errorf("hyperswitch response missing payment_id")
	}
	return paymentID, clientSecret, nil
}

// cancelHyperswitchPayment cancels a payment via Hyperswitch.
func (s *BillingService) cancelHyperswitchPayment(ctx context.Context, paymentID string) error {
	_, err := s.hyperswitchRequest(ctx, http.MethodPost, "/payments/"+paymentID+"/cancel", nil)
	return err
}

// hyperswitchRequest sends an authenticated JSON request to the Hyperswitch API.
func (s *BillingService) hyperswitchRequest(ctx context.Context, method, path string, body any) (map[string]any, error) {
	var bodyReader io.Reader
	if body != nil {
		data, err := json.Marshal(body)
		if err != nil {
			return nil, fmt.Errorf("marshal request body: %w", err)
		}
		bodyReader = bytes.NewReader(data)
	}

	url := s.baseURL + path
	req, err := http.NewRequestWithContext(ctx, method, url, bodyReader)
	if err != nil {
		return nil, fmt.Errorf("create request: %w", err)
	}

	req.Header.Set("Content-Type", "application/json")
	req.Header.Set("Accept", "application/json")
	req.Header.Set("api-key", s.apiKey)

	resp, err := s.httpClient.Do(req)
	if err != nil {
		return nil, fmt.Errorf("execute request: %w", err)
	}
	defer func() { _ = resp.Body.Close() }()

	respData, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("read response body: %w", err)
	}

	if resp.StatusCode >= 400 {
		return nil, fmt.Errorf("hyperswitch API error (status %d): %s", resp.StatusCode, string(respData))
	}

	var result map[string]any
	if len(respData) > 0 {
		if err := json.Unmarshal(respData, &result); err != nil {
			return nil, fmt.Errorf("decode response: %w", err)
		}
	}
	return result, nil
}

// --- helpers ---

// extractPaymentID retrieves the payment_id from a webhook content map.
func extractPaymentID(content map[string]any) string {
	return extractStringField(content, "payment_id", "id")
}

// extractStringField returns the first non-empty string value for the given keys.
func extractStringField(m map[string]any, keys ...string) string {
	for _, k := range keys {
		if v, ok := m[k].(string); ok && v != "" {
			return v
		}
	}
	return ""
}

package config

import (
	"fmt"
	"math/bits"
	"strings"

	"github.com/spf13/viper"
)

// Config holds all configuration for the application.
type Config struct {
	Server     ServerConfig
	Database   DatabaseConfig
	Valkey     ValkeyConfig
	GRPC       GRPCConfig
	OTel       OTelConfig
	Keycloak   KeycloakConfig
	CORS       CORSConfig
	RateLimit  RateLimitConfig
	Queue      QueueConfig
	Encryption EncryptionConfig
	SeaweedFS  SeaweedFSConfig
	Upload     UploadConfig
	PostHog      PostHogConfig
	Hyperswitch  HyperswitchConfig
	LiveKit      LiveKitConfig
	ClickHouse   ClickHouseConfig
	TTS          TTSConfig
	STT          STTConfig
	EBPF         EBPFConfig
	Meta         MetaConfig
}

// MetaConfig holds Meta WhatsApp Business API settings.
type MetaConfig struct {
	AccessToken   string `mapstructure:"access_token"`
	PhoneNumberID string `mapstructure:"phone_number_id"`
	AppSecret     string `mapstructure:"app_secret"`    // for webhook HMAC verification
	WebhookToken  string `mapstructure:"webhook_token"` // hub.verify_token
}

// ClickHouseConfig holds ClickHouse connection and vector backend settings.
type ClickHouseConfig struct {
	Host     string `mapstructure:"host"`
	Port     int    `mapstructure:"port"`
	Database string `mapstructure:"database"`
	User     string `mapstructure:"user"`
	Password string `mapstructure:"password"`
	// VectorBackend selects the default vector storage backend: "pgvector" or "clickhouse".
	VectorBackend string `mapstructure:"vector_backend"`
	// ChunkThreshold is the per-org chunk count above which ClickHouse is preferred.
	ChunkThreshold int64 `mapstructure:"chunk_threshold"`
}

// PostHogConfig holds PostHog analytics settings.
// PostHog is opt-in: when APIKey is empty no events are sent.
type PostHogConfig struct {
	APIKey string `mapstructure:"api_key"`
	Host   string `mapstructure:"host"`
}

// HyperswitchConfig holds Hyperswitch payment orchestration settings.
type HyperswitchConfig struct {
	BaseURL        string `mapstructure:"base_url"`
	APIKey         string `mapstructure:"api_key"`
	WebhookSecret  string `mapstructure:"webhook_secret"`
	RazorpayKeyID  string `mapstructure:"razorpay_key_id"`
}

// LiveKitConfig holds LiveKit WebRTC server settings.
type LiveKitConfig struct {
	// APIURL is the LiveKit server HTTP(S) URL for RoomService API calls.
	APIURL string `mapstructure:"api_url"`
	// WSURL is the WebSocket URL returned to frontend clients for room connections.
	WSURL     string `mapstructure:"ws_url"`
	APIKey    string `mapstructure:"api_key"`
	APISecret string `mapstructure:"api_secret"`
}

// TTSConfig holds text-to-speech provider settings.
type TTSConfig struct {
	// Provider selects the active TTS backend: "cartesia" or "piper".
	Provider string `mapstructure:"provider"`

	// Cartesia Sonic API settings.
	CartesiaAPIKey  string `mapstructure:"cartesia_api_key"`
	CartesiaVoiceID string `mapstructure:"cartesia_voice_id"`
	CartesiaModel   string `mapstructure:"cartesia_model"`
	CartesiaBaseURL string `mapstructure:"cartesia_base_url"`

	// Piper self-hosted TTS settings.
	PiperEndpoint string `mapstructure:"piper_endpoint"`
	PiperVoice    string `mapstructure:"piper_voice"`
}

// STTConfig holds speech-to-text provider settings.
// Provider selects the backend: "deepgram" (cloud) or "whisper" (self-hosted).
// When Provider is empty, Deepgram is used if an API key is set, otherwise whisper.
type STTConfig struct {
	Provider        string `mapstructure:"provider"`
	DeepgramAPIKey  string `mapstructure:"deepgram_api_key"`
	DeepgramModel   string `mapstructure:"deepgram_model"`
	DeepgramBaseURL string `mapstructure:"deepgram_base_url"`
	WhisperEndpoint string `mapstructure:"whisper_endpoint"`
	WhisperModel    string `mapstructure:"whisper_model"`
}

// EBPFConfig holds eBPF feature flags. All features default to false — opt-in only.
// Kernel requirement: Linux ≥ 5.8 with CONFIG_DEBUG_INFO_BTF=y.
//
// Master switch: set RAVEN_EBPF_ENABLED=true to activate the subsystem.
// When false (the default) no eBPF code runs regardless of individual flags.
// On non-Linux platforms the subsystem is always a no-op regardless of this flag.
type EBPFConfig struct {
	// Enabled is the master switch for the entire eBPF subsystem.
	// Set RAVEN_EBPF_ENABLED=true to activate. All other flags are ignored when false.
	Enabled              bool     `mapstructure:"enabled"`
	ObservabilityEnabled bool     `mapstructure:"observability_enabled"`
	AuditEnabled         bool     `mapstructure:"audit_enabled"`
	AuditIPAllowlist     []string `mapstructure:"audit_ip_allowlist"`
	AuditExecAllowlist   []string `mapstructure:"audit_exec_allowlist"`
	// AuditRingBufferSize is the BPF ring buffer size in bytes. Must be a power of 2.
	AuditRingBufferSize int    `mapstructure:"audit_ring_buffer_size"`
	XDPEnabled          bool   `mapstructure:"xdp_enabled"`
	XDPInterface        string `mapstructure:"xdp_interface"`
}

// QueueConfig holds Asynq job queue settings.
type QueueConfig struct {
	Concurrency int `mapstructure:"concurrency"`
	MaxRetry    int `mapstructure:"max_retry"`
}

// EncryptionConfig holds settings for data-at-rest encryption (e.g. LLM API keys).
type EncryptionConfig struct {
	AESKey string `mapstructure:"aes_key"`
}

// SeaweedFSConfig holds SeaweedFS connection settings.
type SeaweedFSConfig struct {
	MasterURL string `mapstructure:"master_url"`
}

// UploadConfig holds file upload settings.
type UploadConfig struct {
	MaxSizeBytes int64    `mapstructure:"max_size_bytes"`
	AllowedTypes []string `mapstructure:"allowed_types"`
}

// KeycloakConfig holds Keycloak/OIDC settings for JWT validation.
type KeycloakConfig struct {
	IssuerURL string `mapstructure:"issuer_url"`
	Audience  string `mapstructure:"audience"`
	// APIKeyEnabled enables the unvalidated API-key stub (see issue-24).
	// Disabled by default; set RAVEN_KEYCLOAK_APIKEYENABLED=true only in
	// development environments until the real DB-backed lookup is implemented.
	APIKeyEnabled bool `mapstructure:"api_key_enabled"`
}

// CORSConfig holds Cross-Origin Resource Sharing settings.
type CORSConfig struct {
	AllowedOrigins []string `mapstructure:"allowed_origins"`
}

// RateLimitConfig holds rate limiting defaults.
type RateLimitConfig struct {
	DefaultUserLimit int `mapstructure:"default_user_limit"`
	DefaultOrgLimit  int `mapstructure:"default_org_limit"`
}

// ServerConfig holds HTTP server settings.
type ServerConfig struct {
	Port int    `mapstructure:"port"`
	Mode string `mapstructure:"mode"`
}

// DatabaseConfig holds database connection settings.
type DatabaseConfig struct {
	URL string `mapstructure:"url"`
}

// ValkeyConfig holds Valkey (Redis-compatible) connection settings.
type ValkeyConfig struct {
	URL string `mapstructure:"url"`
}

// GRPCConfig holds gRPC client settings for the AI worker.
type GRPCConfig struct {
	WorkerAddr string `mapstructure:"worker_addr"`
}

// OTelConfig holds OpenTelemetry settings.
type OTelConfig struct {
	Endpoint    string `mapstructure:"endpoint"`
	ServiceName string `mapstructure:"service_name"`
	Enabled     bool   `mapstructure:"enabled"`
}

// Load reads configuration from environment variables and optional config file.
func Load() (*Config, error) {
	v := viper.New()

	// Set defaults
	v.SetDefault("server.port", 8080)
	v.SetDefault("server.mode", "debug")
	v.SetDefault("grpc.worker_addr", "localhost:50051")
	v.SetDefault("otel.endpoint", "")
	v.SetDefault("otel.service_name", "raven-api")
	v.SetDefault("otel.enabled", false)
	v.SetDefault("keycloak.issuer_url", "http://localhost:8080/auth/realms/raven")
	v.SetDefault("keycloak.audience", "raven")
	// CORS allowed origins can be overridden via the RAVEN_CORS_ALLOWED_ORIGINS
	// environment variable as a comma-separated list.
	// Example: RAVEN_CORS_ALLOWED_ORIGINS=https://app1.com,https://app2.com
	v.SetDefault("cors.allowed_origins", []string{
		"http://localhost:5173",
		"https://raven-frontend.pages.dev",
	})
	// Explicitly bind so Viper surfaces the env var when unmarshaling slice fields.
	_ = v.BindEnv("cors.allowed_origins", "RAVEN_CORS_ALLOWED_ORIGINS")
	v.SetDefault("ratelimit.default_user_limit", 1000)
	v.SetDefault("ratelimit.default_org_limit", 10000)
	v.SetDefault("queue.concurrency", 10)
	v.SetDefault("queue.max_retry", 5)
	v.SetDefault("seaweedfs.master_url", "http://seaweedfs-master:9333")
	v.SetDefault("posthog.api_key", "")
	v.SetDefault("posthog.host", "https://us.i.posthog.com")
	v.SetDefault("hyperswitch.base_url", "http://localhost:8090")
	v.SetDefault("hyperswitch.api_key", "")
	v.SetDefault("hyperswitch.webhook_secret", "")
	v.SetDefault("hyperswitch.razorpay_key_id", "")
	v.SetDefault("livekit.api_url", "http://localhost:7880")
	v.SetDefault("livekit.ws_url", "ws://localhost:7880")
	v.SetDefault("livekit.api_key", "devkey")
	v.SetDefault("livekit.api_secret", "devsecret")
	v.SetDefault("clickhouse.host", "")
	v.SetDefault("clickhouse.port", 9000)
	v.SetDefault("clickhouse.database", "raven")
	v.SetDefault("clickhouse.user", "default")
	v.SetDefault("clickhouse.password", "")
	v.SetDefault("clickhouse.vector_backend", "pgvector")
	v.SetDefault("clickhouse.chunk_threshold", 5000000)
	// TTS defaults
	v.SetDefault("tts.provider", "cartesia")
	v.SetDefault("tts.cartesia_api_key", "")
	v.SetDefault("tts.cartesia_voice_id", "")
	v.SetDefault("tts.cartesia_model", "sonic-2")
	v.SetDefault("tts.cartesia_base_url", "")
	v.SetDefault("tts.piper_endpoint", "http://localhost:5000")
	v.SetDefault("tts.piper_voice", "en_US-amy-medium")
	// STT defaults
	v.SetDefault("stt.provider", "")
	v.SetDefault("stt.deepgram_api_key", "")
	v.SetDefault("stt.deepgram_model", "nova-2")
	v.SetDefault("stt.deepgram_base_url", "https://api.deepgram.com")
	v.SetDefault("stt.whisper_endpoint", "http://localhost:8000")
	v.SetDefault("stt.whisper_model", "large-v3")
	// eBPF defaults — master switch off; safe for non-Linux and existing deployments
	v.SetDefault("ebpf.enabled", false)
	v.SetDefault("ebpf.observability_enabled", false)
	v.SetDefault("ebpf.audit_enabled", false)
	v.SetDefault("ebpf.audit_ip_allowlist", []string{})
	v.SetDefault("ebpf.audit_exec_allowlist", []string{})
	v.SetDefault("ebpf.audit_ring_buffer_size", 1048576)
	v.SetDefault("ebpf.xdp_enabled", false)
	v.SetDefault("ebpf.xdp_interface", "eth0")
	// Meta WhatsApp Business API defaults
	v.SetDefault("meta.access_token", "")
	v.SetDefault("meta.phone_number_id", "")
	v.SetDefault("meta.app_secret", "")
	v.SetDefault("meta.webhook_token", "")
	v.SetDefault("upload.max_size_bytes", 52428800) // 50 MB
	v.SetDefault("upload.allowed_types", []string{
		"application/pdf",
		"application/vnd.openxmlformats-officedocument.wordprocessingml.document",
		"application/vnd.openxmlformats-officedocument.presentationml.presentation",
		"text/html",
		"text/markdown",
		"text/plain",
		"text/csv",
	})

	// Config file (optional)
	v.SetConfigName("config")
	v.SetConfigType("yaml")
	v.AddConfigPath(".")
	v.AddConfigPath("./config")

	// Environment variables
	v.SetEnvPrefix("RAVEN")
	v.SetEnvKeyReplacer(strings.NewReplacer(".", "_"))
	v.AutomaticEnv()

	// Explicitly bind nested keys — AutomaticEnv alone does not reliably surface
	// dotted keys during Unmarshal in all viper versions.
	_ = v.BindEnv("database.url", "RAVEN_DATABASE_URL")
	_ = v.BindEnv("valkey.url", "RAVEN_VALKEY_URL")
	_ = v.BindEnv("grpc.worker_addr", "RAVEN_GRPC_WORKER_ADDR")
	_ = v.BindEnv("keycloak.issuer_url", "RAVEN_KEYCLOAK_ISSUER_URL")
	_ = v.BindEnv("keycloak.audience", "RAVEN_KEYCLOAK_AUDIENCE")
	_ = v.BindEnv("server.port", "RAVEN_SERVER_PORT")
	_ = v.BindEnv("server.mode", "RAVEN_SERVER_MODE")
	_ = v.BindEnv("clickhouse.host", "RAVEN_CLICKHOUSE_HOST")
	_ = v.BindEnv("clickhouse.port", "RAVEN_CLICKHOUSE_PORT")
	_ = v.BindEnv("clickhouse.database", "RAVEN_CLICKHOUSE_DATABASE")
	_ = v.BindEnv("clickhouse.user", "RAVEN_CLICKHOUSE_USER")
	_ = v.BindEnv("clickhouse.password", "RAVEN_CLICKHOUSE_PASSWORD")
	_ = v.BindEnv("clickhouse.vector_backend", "RAVEN_CLICKHOUSE_VECTOR_BACKEND")
	_ = v.BindEnv("clickhouse.chunk_threshold", "RAVEN_CLICKHOUSE_CHUNK_THRESHOLD")
	_ = v.BindEnv("tts.provider", "RAVEN_TTS_PROVIDER")
	_ = v.BindEnv("tts.cartesia_api_key", "RAVEN_TTS_CARTESIA_API_KEY")
	_ = v.BindEnv("tts.cartesia_voice_id", "RAVEN_TTS_CARTESIA_VOICE_ID")
	_ = v.BindEnv("tts.cartesia_model", "RAVEN_TTS_CARTESIA_MODEL")
	_ = v.BindEnv("tts.cartesia_base_url", "RAVEN_TTS_CARTESIA_BASE_URL")
	_ = v.BindEnv("tts.piper_endpoint", "RAVEN_TTS_PIPER_ENDPOINT")
	_ = v.BindEnv("tts.piper_voice", "RAVEN_TTS_PIPER_VOICE")
	_ = v.BindEnv("stt.provider", "RAVEN_STT_PROVIDER")
	_ = v.BindEnv("stt.deepgram_api_key", "RAVEN_STT_DEEPGRAM_API_KEY")
	_ = v.BindEnv("stt.deepgram_model", "RAVEN_STT_DEEPGRAM_MODEL")
	_ = v.BindEnv("stt.deepgram_base_url", "RAVEN_STT_DEEPGRAM_BASE_URL")
	_ = v.BindEnv("stt.whisper_endpoint", "RAVEN_STT_WHISPER_ENDPOINT")
	_ = v.BindEnv("stt.whisper_model", "RAVEN_STT_WHISPER_MODEL")
	_ = v.BindEnv("livekit.api_url", "RAVEN_LIVEKIT_API_URL")
	_ = v.BindEnv("livekit.ws_url", "RAVEN_LIVEKIT_WS_URL")
	_ = v.BindEnv("livekit.api_key", "RAVEN_LIVEKIT_API_KEY")
	_ = v.BindEnv("livekit.api_secret", "RAVEN_LIVEKIT_API_SECRET")
	_ = v.BindEnv("encryption.aes_key", "RAVEN_ENCRYPTION_AES_KEY")
	_ = v.BindEnv("otel.endpoint", "RAVEN_OTEL_ENDPOINT")
	_ = v.BindEnv("otel.service_name", "RAVEN_OTEL_SERVICE_NAME")
	_ = v.BindEnv("otel.enabled", "RAVEN_OTEL_ENABLED")
	_ = v.BindEnv("hyperswitch.base_url", "RAVEN_HYPERSWITCH_BASE_URL")
	_ = v.BindEnv("hyperswitch.api_key", "RAVEN_HYPERSWITCH_API_KEY")
	_ = v.BindEnv("hyperswitch.webhook_secret", "RAVEN_HYPERSWITCH_WEBHOOK_SECRET")
	_ = v.BindEnv("hyperswitch.razorpay_key_id", "RAVEN_HYPERSWITCH_RAZORPAY_KEY_ID")
	_ = v.BindEnv("ebpf.enabled", "RAVEN_EBPF_ENABLED")
	_ = v.BindEnv("ebpf.observability_enabled", "RAVEN_EBPF_OBSERVABILITY_ENABLED")
	_ = v.BindEnv("ebpf.audit_enabled", "RAVEN_EBPF_AUDIT_ENABLED")
	_ = v.BindEnv("ebpf.audit_ip_allowlist", "RAVEN_EBPF_AUDIT_IP_ALLOWLIST")
	_ = v.BindEnv("ebpf.audit_exec_allowlist", "RAVEN_EBPF_AUDIT_EXEC_ALLOWLIST")
	_ = v.BindEnv("ebpf.audit_ring_buffer_size", "RAVEN_EBPF_AUDIT_RING_BUFFER_SIZE")
	_ = v.BindEnv("ebpf.xdp_enabled", "RAVEN_EBPF_XDP_ENABLED")
	_ = v.BindEnv("ebpf.xdp_interface", "RAVEN_EBPF_XDP_INTERFACE")

	// Try to read config file but don't fail if not found
	_ = v.ReadInConfig()

	var cfg Config
	if err := v.Unmarshal(&cfg); err != nil {
		return nil, err
	}

	if cfg.RateLimit.DefaultUserLimit <= 0 {
		return nil, fmt.Errorf("ratelimit.default_user_limit must be > 0, got %d", cfg.RateLimit.DefaultUserLimit)
	}
	if cfg.RateLimit.DefaultOrgLimit <= 0 {
		return nil, fmt.Errorf("ratelimit.default_org_limit must be > 0, got %d", cfg.RateLimit.DefaultOrgLimit)
	}

	// Validate ring buffer size when eBPF is enabled — catches misconfiguration before any BPF load.
	// Validated even when individual AuditEnabled=false so that a stale invalid value doesn't
	// silently survive until someone enables audit later.
	if cfg.EBPF.Enabled {
		size := cfg.EBPF.AuditRingBufferSize
		if size <= 0 || bits.OnesCount(uint(size)) != 1 {
			return nil, fmt.Errorf("ebpf.audit_ring_buffer_size must be a power of 2 > 0, got %d", size)
		}
	}

	return &cfg, nil
}

