package telemetry

import (
	"context"
	"log/slog"
	"os"
)

// writerStderr is a thin wrapper so the JSON handler writes to os.Stderr.
type writerStderr struct{}

func (writerStderr) Write(p []byte) (int, error) { return os.Stderr.Write(p) }

// multiHandler fans out slog records to multiple handlers.
type multiHandler struct {
	handlers []slog.Handler
}

func newMultiHandler(handlers ...slog.Handler) *multiHandler {
	return &multiHandler{handlers: handlers}
}

func (m *multiHandler) Enabled(ctx context.Context, level slog.Level) bool {
	for _, h := range m.handlers {
		if h.Enabled(ctx, level) {
			return true
		}
	}
	return false
}

func (m *multiHandler) Handle(ctx context.Context, r slog.Record) error {
	for _, h := range m.handlers {
		if h.Enabled(ctx, r.Level) {
			if err := h.Handle(ctx, r.Clone()); err != nil {
				return err
			}
		}
	}
	return nil
}

func (m *multiHandler) WithAttrs(attrs []slog.Attr) slog.Handler {
	handlers := make([]slog.Handler, len(m.handlers))
	for i, h := range m.handlers {
		handlers[i] = h.WithAttrs(attrs)
	}
	return &multiHandler{handlers: handlers}
}

func (m *multiHandler) WithGroup(name string) slog.Handler {
	handlers := make([]slog.Handler, len(m.handlers))
	for i, h := range m.handlers {
		handlers[i] = h.WithGroup(name)
	}
	return &multiHandler{handlers: handlers}
}

package telemetry

import (
	"context"
	"log/slog"

	"go.opentelemetry.io/otel"
	"go.opentelemetry.io/otel/attribute"
	"go.opentelemetry.io/otel/metric"
)

const meterName = "github.com/ravencloak-org/Raven/internal/telemetry"

// Metrics holds pre-created OTEL instruments for business-level observability.
// All methods are safe for concurrent use.  When the global MeterProvider is
// a no-op (OTel not configured) the instruments silently discard data.
type Metrics struct {
	// HTTP
	httpRequestsTotal metric.Int64Counter

	// Chat completions
	chatCompletionsTotal  metric.Int64Counter
	chatTokensTotal       metric.Int64Counter
	chatCompletionLatency metric.Float64Histogram

	// Voice sessions
	voiceSessionsCreated  metric.Int64Counter
	voiceSessionsActive   metric.Int64UpDownCounter
	voiceTurnsTotal       metric.Int64Counter

	// WhatsApp
	whatsappCallsTotal    metric.Int64Counter
	whatsappMessagesTotal metric.Int64Counter
}

// NewMetrics creates and registers all business metric instruments.
// It never returns an error; creation failures are logged and the
// corresponding instrument is left nil (methods check before recording).
func NewMetrics() *Metrics {
	meter := otel.Meter(meterName)
	m := &Metrics{}

	var err error

	// --- HTTP ---
	m.httpRequestsTotal, err = meter.Int64Counter("raven.http.requests.total",
		metric.WithDescription("Total HTTP requests by method, route and status"),
		metric.WithUnit("{request}"),
	)
	logMetricErr("raven.http.requests.total", err)

	// --- Chat ---
	m.chatCompletionsTotal, err = meter.Int64Counter("raven.chat.completions.total",
		metric.WithDescription("Total chat completion requests"),
		metric.WithUnit("{completion}"),
	)
	logMetricErr("raven.chat.completions.total", err)

	m.chatTokensTotal, err = meter.Int64Counter("raven.chat.tokens.total",
		metric.WithDescription("Total tokens generated in chat completions"),
		metric.WithUnit("{token}"),
	)
	logMetricErr("raven.chat.tokens.total", err)

	m.chatCompletionLatency, err = meter.Float64Histogram("raven.chat.completion.latency",
		metric.WithDescription("Latency of chat completion requests"),
		metric.WithUnit("ms"),
	)
	logMetricErr("raven.chat.completion.latency", err)

	// --- Voice ---
	m.voiceSessionsCreated, err = meter.Int64Counter("raven.voice.sessions.created",
		metric.WithDescription("Total voice sessions created"),
		metric.WithUnit("{session}"),
	)
	logMetricErr("raven.voice.sessions.created", err)

	m.voiceSessionsActive, err = meter.Int64UpDownCounter("raven.voice.sessions.active",
		metric.WithDescription("Currently active voice sessions"),
		metric.WithUnit("{session}"),
	)
	logMetricErr("raven.voice.sessions.active", err)

	m.voiceTurnsTotal, err = meter.Int64Counter("raven.voice.turns.total",
		metric.WithDescription("Total voice turns appended"),
		metric.WithUnit("{turn}"),
	)
	logMetricErr("raven.voice.turns.total", err)

	// --- WhatsApp ---
	m.whatsappCallsTotal, err = meter.Int64Counter("raven.whatsapp.calls.total",
		metric.WithDescription("Total WhatsApp calls initiated"),
		metric.WithUnit("{call}"),
	)
	logMetricErr("raven.whatsapp.calls.total", err)

	m.whatsappMessagesTotal, err = meter.Int64Counter("raven.whatsapp.messages.total",
		metric.WithDescription("Total WhatsApp messages processed"),
		metric.WithUnit("{message}"),
	)
	logMetricErr("raven.whatsapp.messages.total", err)

	return m
}

func logMetricErr(name string, err error) {
	if err != nil {
		slog.Warn("failed to create metric instrument", "name", name, "error", err)
	}
}

// --- HTTP recording helpers ---

// RecordHTTPRequest increments the HTTP request counter.
func (m *Metrics) RecordHTTPRequest(ctx context.Context, method, route string, status int) {
	if m.httpRequestsTotal == nil {
		return
	}
	m.httpRequestsTotal.Add(ctx, 1,
		metric.WithAttributes(
			attribute.String("http.method", method),
			attribute.String("http.route", route),
			attribute.Int("http.status_code", status),
		),
	)
}

// --- Chat recording helpers ---

// RecordChatCompletion records a chat completion event.
func (m *Metrics) RecordChatCompletion(ctx context.Context, orgID, kbID, model string) {
	if m.chatCompletionsTotal == nil {
		return
	}
	m.chatCompletionsTotal.Add(ctx, 1,
		metric.WithAttributes(
			attribute.String("org_id", orgID),
			attribute.String("kb_id", kbID),
			attribute.String("model", model),
		),
	)
}

// RecordChatTokens records token usage for a completion.
func (m *Metrics) RecordChatTokens(ctx context.Context, orgID string, tokens int64) {
	if m.chatTokensTotal == nil {
		return
	}
	m.chatTokensTotal.Add(ctx, tokens,
		metric.WithAttributes(attribute.String("org_id", orgID)),
	)
}

// RecordChatLatency records the latency of a chat completion in milliseconds.
func (m *Metrics) RecordChatLatency(ctx context.Context, orgID string, latencyMs float64) {
	if m.chatCompletionLatency == nil {
		return
	}
	m.chatCompletionLatency.Record(ctx, latencyMs,
		metric.WithAttributes(attribute.String("org_id", orgID)),
	)
}

// --- Voice recording helpers ---

// RecordVoiceSessionCreated increments the voice session created counter.
func (m *Metrics) RecordVoiceSessionCreated(ctx context.Context, orgID string) {
	if m.voiceSessionsCreated == nil {
		return
	}
	m.voiceSessionsCreated.Add(ctx, 1,
		metric.WithAttributes(attribute.String("org_id", orgID)),
	)
}

// RecordVoiceSessionActive adjusts the active voice session gauge (delta: +1 or -1).
func (m *Metrics) RecordVoiceSessionActive(ctx context.Context, orgID string, delta int64) {
	if m.voiceSessionsActive == nil {
		return
	}
	m.voiceSessionsActive.Add(ctx, delta,
		metric.WithAttributes(attribute.String("org_id", orgID)),
	)
}

// RecordVoiceTurn increments the voice turn counter.
func (m *Metrics) RecordVoiceTurn(ctx context.Context, orgID string) {
	if m.voiceTurnsTotal == nil {
		return
	}
	m.voiceTurnsTotal.Add(ctx, 1,
		metric.WithAttributes(attribute.String("org_id", orgID)),
	)
}

// --- WhatsApp recording helpers ---

// RecordWhatsAppCall increments the WhatsApp call counter.
func (m *Metrics) RecordWhatsAppCall(ctx context.Context, orgID, direction string) {
	if m.whatsappCallsTotal == nil {
		return
	}
	m.whatsappCallsTotal.Add(ctx, 1,
		metric.WithAttributes(
			attribute.String("org_id", orgID),
			attribute.String("direction", direction),
		),
	)
}

// RecordWhatsAppMessage increments the WhatsApp message counter.
func (m *Metrics) RecordWhatsAppMessage(ctx context.Context, orgID, msgType string) {
	if m.whatsappMessagesTotal == nil {
		return
	}
	m.whatsappMessagesTotal.Add(ctx, 1,
		metric.WithAttributes(
			attribute.String("org_id", orgID),
			attribute.String("type", msgType),
		),
	)
}

package middleware

import (
	"fmt"
	"log/slog"
	"time"

	"github.com/gin-gonic/gin"
	"go.opentelemetry.io/otel"
	"go.opentelemetry.io/otel/metric"
	semconv "go.opentelemetry.io/otel/semconv/v1.26.0"
	"go.opentelemetry.io/otel/trace"

	"github.com/ravencloak-org/Raven/internal/telemetry"
)

const instrumentationName = "github.com/ravencloak-org/Raven/internal/middleware"

// OTelMiddleware returns a Gin middleware that creates a span per HTTP request,
// records request duration as a histogram metric, sets the X-Trace-ID
// response header, and emits a structured slog entry with trace_id, org_id
// and latency_ms fields for log aggregation.
//
// When the global TracerProvider is a no-op (i.e. OTel is not configured) the
// middleware still runs but produces zero overhead because the SDK short-
// circuits all recording.
func OTelMiddleware() gin.HandlerFunc {
	tracer := otel.Tracer(instrumentationName)
	meter := otel.Meter(instrumentationName)
	bm := telemetry.NewMetrics()

	// Best-effort histogram; if creation fails we continue without metrics.
	duration, _ := meter.Float64Histogram(
		"http.server.request.duration",
		metric.WithDescription("Duration of HTTP server requests"),
		metric.WithUnit("s"),
	)

	return func(c *gin.Context) {
		start := time.Now()

		// Derive a readable span name: "GET /healthz".
		spanName := fmt.Sprintf("%s %s", c.Request.Method, c.FullPath())
		if c.FullPath() == "" {
			spanName = fmt.Sprintf("%s %s", c.Request.Method, c.Request.URL.Path)
		}

		ctx, span := tracer.Start(c.Request.Context(), spanName,
			trace.WithSpanKind(trace.SpanKindServer),
			trace.WithAttributes(
				semconv.HTTPRequestMethodKey.String(c.Request.Method),
				semconv.URLPath(c.Request.URL.Path),
			),
		)
		defer span.End()

		// Propagate the trace context into the request so downstream
		// handlers and services can join the trace.
		c.Request = c.Request.WithContext(ctx)

		// Expose the trace ID as a response header for easy debugging.
		traceID := ""
		if span.SpanContext().HasTraceID() {
			traceID = span.SpanContext().TraceID().String()
			c.Header("X-Trace-ID", traceID)
		}

		// Process request.
		c.Next()

		// After the request completes record status on the span.
		status := c.Writer.Status()
		span.SetAttributes(
			semconv.HTTPResponseStatusCode(status),
			semconv.HTTPRoute(c.FullPath()),
		)

		elapsed := time.Since(start)
		elapsedSec := elapsed.Seconds()
		latencyMs := float64(elapsed.Milliseconds())
		route := c.FullPath()

		// Record duration metric.
		if duration != nil {
			duration.Record(ctx,
				elapsedSec,
				metric.WithAttributes(
					semconv.HTTPRequestMethodKey.String(c.Request.Method),
					semconv.HTTPRoute(route),
					semconv.HTTPResponseStatusCode(status),
				),
			)
		}

		// Record business-level HTTP request counter.
		bm.RecordHTTPRequest(ctx, c.Request.Method, route, status)

		// Emit a structured log line with trace context for log aggregation.
		// The otelslog bridge automatically correlates trace_id/span_id when
		// the context carries a span.
		orgID, _ := c.Get(string(ContextKeyOrgID))
		orgStr, _ := orgID.(string)

		slog.InfoContext(ctx, "http request",
			slog.String("method", c.Request.Method),
			slog.String("path", c.Request.URL.Path),
			slog.String("route", route),
			slog.Int("status", status),
			slog.Float64("latency_ms", latencyMs),
			slog.String("trace_id", traceID),
			slog.String("org_id", orgStr),
			slog.String("user_agent", c.Request.UserAgent()),
			slog.String("client_ip", c.ClientIP()),
		)
	}
}

package telemetry

import (
	"bytes"
	"context"
	"log/slog"
	"strings"
	"testing"
)

func TestMultiHandler_FansOutToAll(t *testing.T) {
	var buf1, buf2 bytes.Buffer
	h1 := slog.NewJSONHandler(&buf1, &slog.HandlerOptions{Level: slog.LevelInfo})
	h2 := slog.NewJSONHandler(&buf2, &slog.HandlerOptions{Level: slog.LevelInfo})

	mh := newMultiHandler(h1, h2)
	logger := slog.New(mh)

	logger.InfoContext(context.Background(), "test message", slog.String("key", "value"))

	if !strings.Contains(buf1.String(), "test message") {
		t.Error("expected handler 1 to receive the log message")
	}
	if !strings.Contains(buf2.String(), "test message") {
		t.Error("expected handler 2 to receive the log message")
	}
}

func TestMultiHandler_Enabled_AnyEnabled(t *testing.T) {
	debug := slog.NewJSONHandler(&bytes.Buffer{}, &slog.HandlerOptions{Level: slog.LevelDebug})
	warn := slog.NewJSONHandler(&bytes.Buffer{}, &slog.HandlerOptions{Level: slog.LevelWarn})

	mh := newMultiHandler(debug, warn)

	// Debug should be enabled because at least one handler (debug) accepts it.
	if !mh.Enabled(context.Background(), slog.LevelDebug) {
		t.Error("expected Enabled to return true when at least one handler accepts the level")
	}
}

func TestMultiHandler_WithAttrs(t *testing.T) {
	var buf bytes.Buffer
	h := slog.NewJSONHandler(&buf, nil)
	mh := newMultiHandler(h)

	mh2 := mh.WithAttrs([]slog.Attr{slog.String("service", "raven")})
	logger := slog.New(mh2)
	logger.Info("with attrs")

	if !strings.Contains(buf.String(), "raven") {
		t.Error("expected WithAttrs to propagate to underlying handler")
	}
}

func TestMultiHandler_WithGroup(t *testing.T) {
	var buf bytes.Buffer
	h := slog.NewJSONHandler(&buf, nil)
	mh := newMultiHandler(h)

	mh2 := mh.WithGroup("request")
	logger := slog.New(mh2)
	logger.Info("with group", slog.String("path", "/api"))

	if !strings.Contains(buf.String(), "request") {
		t.Error("expected WithGroup to propagate to underlying handler")
	}
}

package telemetry

import (
	"context"
	"testing"

	"go.opentelemetry.io/otel"
	sdkmetric "go.opentelemetry.io/otel/sdk/metric"
	"go.opentelemetry.io/otel/sdk/metric/metricdata"
)

func setupMetricReader(t *testing.T) *sdkmetric.ManualReader {
	t.Helper()
	reader := sdkmetric.NewManualReader()
	mp := sdkmetric.NewMeterProvider(sdkmetric.WithReader(reader))
	otel.SetMeterProvider(mp)
	t.Cleanup(func() { _ = mp.Shutdown(context.Background()) })
	return reader
}

func collectMetricNames(t *testing.T, reader *sdkmetric.ManualReader) map[string]bool {
	t.Helper()
	var rm metricdata.ResourceMetrics
	if err := reader.Collect(context.Background(), &rm); err != nil {
		t.Fatalf("failed to collect metrics: %v", err)
	}
	names := make(map[string]bool)
	for _, sm := range rm.ScopeMetrics {
		for _, m := range sm.Metrics {
			names[m.Name] = true
		}
	}
	return names
}

func TestNewMetrics_CreatesAllInstruments(t *testing.T) {
	reader := setupMetricReader(t)
	m := NewMetrics()

	// Record one of each to ensure instruments are exercised.
	ctx := context.Background()
	m.RecordHTTPRequest(ctx, "GET", "/healthz", 200)
	m.RecordChatCompletion(ctx, "org-1", "kb-1", "gpt-4")
	m.RecordChatTokens(ctx, "org-1", 42)
	m.RecordChatLatency(ctx, "org-1", 123.4)
	m.RecordVoiceSessionCreated(ctx, "org-1")
	m.RecordVoiceSessionActive(ctx, "org-1", 1)
	m.RecordVoiceTurn(ctx, "org-1")
	m.RecordWhatsAppCall(ctx, "org-1", "outbound")
	m.RecordWhatsAppMessage(ctx, "org-1", "text")

	names := collectMetricNames(t, reader)

	expected := []string{
		"raven.http.requests.total",
		"raven.chat.completions.total",
		"raven.chat.tokens.total",
		"raven.chat.completion.latency",
		"raven.voice.sessions.created",
		"raven.voice.sessions.active",
		"raven.voice.turns.total",
		"raven.whatsapp.calls.total",
		"raven.whatsapp.messages.total",
	}

	for _, name := range expected {
		if !names[name] {
			t.Errorf("expected metric %q to be recorded", name)
		}
	}
}

func TestMetrics_NilInstruments_NoPanic(t *testing.T) {
	// A zero-value Metrics has all nil instruments; methods must not panic.
	m := &Metrics{}
	ctx := context.Background()

	m.RecordHTTPRequest(ctx, "GET", "/", 200)
	m.RecordChatCompletion(ctx, "", "", "")
	m.RecordChatTokens(ctx, "", 0)
	m.RecordChatLatency(ctx, "", 0)
	m.RecordVoiceSessionCreated(ctx, "")
	m.RecordVoiceSessionActive(ctx, "", 1)
	m.RecordVoiceTurn(ctx, "")
	m.RecordWhatsAppCall(ctx, "", "")
	m.RecordWhatsAppMessage(ctx, "", "")
}

// Package telemetry initialises OpenTelemetry tracing, metrics and logging
// for the Raven API.  When no OTLP endpoint is configured the package
// gracefully degrades to no-op providers so the rest of the application works
// without any observable overhead.
package telemetry

import (
	"context"
	"errors"
	"log/slog"

	"go.opentelemetry.io/contrib/bridges/otelslog"
	"go.opentelemetry.io/otel"
	"go.opentelemetry.io/otel/exporters/otlp/otlplog/otlploggrpc"
	"go.opentelemetry.io/otel/exporters/otlp/otlpmetric/otlpmetricgrpc"
	"go.opentelemetry.io/otel/exporters/otlp/otlptrace/otlptracegrpc"
	logGlobal "go.opentelemetry.io/otel/log/global"
	"go.opentelemetry.io/otel/propagation"
	"go.opentelemetry.io/otel/sdk/metric"
	"go.opentelemetry.io/otel/sdk/resource"
	"go.opentelemetry.io/otel/sdk/trace"
	semconv "go.opentelemetry.io/otel/semconv/v1.26.0"

	sdklog "go.opentelemetry.io/otel/sdk/log"
)

// InitProvider sets up a TracerProvider, MeterProvider and LoggerProvider.
//
// If endpoint is non-empty, OTLP gRPC exporters are configured for traces,
// metrics and logs.  Otherwise no-op providers are used so that callers never
// need to nil-check.
//
// When an OTLP endpoint is configured, the global slog default is replaced
// with a multi-handler that writes JSON to stderr AND ships structured logs
// to the collector (with trace_id correlation).
//
// The returned shutdown function flushes pending telemetry and releases
// resources.  It is safe to call even when the providers are no-ops.
func InitProvider(ctx context.Context, serviceName, serviceVersion, endpoint, environment string) (shutdown func(context.Context) error, err error) {
	// Build the OTel resource that describes this service.
	// We use NewSchemaless to avoid schema-URL conflicts with resource.Default().
	res, err := resource.Merge(
		resource.Default(),
		resource.NewSchemaless(
			semconv.ServiceName(serviceName),
			semconv.ServiceVersion(serviceVersion),
			semconv.DeploymentEnvironment(environment),
		),
	)
	if err != nil {
		return nil, err
	}

	// When there is no endpoint we leave the global providers at their
	// defaults (no-op).  Return a no-op shutdown.
	if endpoint == "" {
		return func(context.Context) error { return nil }, nil
	}

	var shutdownFuncs []func(context.Context) error

	// Helper that aggregates all shutdown functions.
	shutdownAll := func(ctx context.Context) error {
		var errs []error
		for _, fn := range shutdownFuncs {
			if e := fn(ctx); e != nil {
				errs = append(errs, e)
			}
		}
		return errors.Join(errs...)
	}

	// --- Trace exporter ---
	traceExporter, err := otlptracegrpc.New(ctx,
		otlptracegrpc.WithEndpoint(endpoint),
		otlptracegrpc.WithInsecure(),
	)
	if err != nil {
		return shutdownAll, err
	}

	tp := trace.NewTracerProvider(
		trace.WithBatcher(traceExporter),
		trace.WithResource(res),
	)
	shutdownFuncs = append(shutdownFuncs, tp.Shutdown)
	otel.SetTracerProvider(tp)

	// --- Metric exporter ---
	metricExporter, err := otlpmetricgrpc.New(ctx,
		otlpmetricgrpc.WithEndpoint(endpoint),
		otlpmetricgrpc.WithInsecure(),
	)
	if err != nil {
		return shutdownAll, err
	}

	mp := metric.NewMeterProvider(
		metric.WithReader(metric.NewPeriodicReader(metricExporter)),
		metric.WithResource(res),
	)
	shutdownFuncs = append(shutdownFuncs, mp.Shutdown)
	otel.SetMeterProvider(mp)

	// --- Log exporter ---
	logExporter, err := otlploggrpc.New(ctx,
		otlploggrpc.WithEndpoint(endpoint),
		otlploggrpc.WithInsecure(),
	)
	if err != nil {
		return shutdownAll, err
	}

	lp := sdklog.NewLoggerProvider(
		sdklog.WithProcessor(sdklog.NewBatchProcessor(logExporter)),
		sdklog.WithResource(res),
	)
	shutdownFuncs = append(shutdownFuncs, lp.Shutdown)
	logGlobal.SetLoggerProvider(lp)

	// Replace the default slog handler with a multi-handler that writes to
	// both stderr (JSON) and the OTLP collector.  The otelslog bridge
	// automatically picks up trace_id / span_id from the context.
	otelHandler := otelslog.NewHandler(serviceName, otelslog.WithLoggerProvider(lp))
	stderrHandler := slog.NewJSONHandler(writerStderr{}, &slog.HandlerOptions{Level: slog.LevelInfo})
	slog.SetDefault(slog.New(newMultiHandler(otelHandler, stderrHandler)))

	// --- Propagation ---
	otel.SetTextMapPropagator(propagation.NewCompositeTextMapPropagator(
		propagation.TraceContext{},
		propagation.Baggage{},
	))

	return shutdownAll, nil
}

