      "name": "chat_completion_failures",
      "description": "Fires when chat completion error rate is high.",
      "condition": "rate(raven_http_requests_total{http_route=~\"/api/v1/chat/.*/completions\",http_status_code=~\"5..\"}[5m]) > 0.1",
      "for": "5m",
      "severity": "critical",
      "action": {
        "type": "webhook",
        "url": "${ALERT_WEBHOOK_URL}",
